// App.js - Skin Analysis Frontend - REBUILT with Interactive Face Detection
import React, { useState, useRef, useEffect, useCallback } from 'react';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

// ============================================================================
// FACE DETECTION HOOK
// ============================================================================
function useFaceDetection(videoRef, isActive) {
  const [faceData, setFaceData] = useState(null);
  const [hasFace, setHasFace] = useState(false);
  const [facePosition, setFacePosition] = useState('none');
  const detectorRef = useRef(null);

  useEffect(() => {
    if (!isActive) return;

    // Try native FaceDetector API (Chrome/Edge on supported platforms)
    if (window.FaceDetector) {
      try {
        detectorRef.current = new window.FaceDetector({ fastMode: true, maxDetectedFaces: 1 });
      } catch(e) {
        detectorRef.current = null;
      }
    }

    const detect = async () => {
      const video = videoRef.current;
      if (!video || video.readyState !== 4) return;

      try {
        if (detectorRef.current) {
          // Native FaceDetector
          const faces = await detectorRef.current.detect(video);
          if (faces.length > 0) {
            const face = faces[0].boundingBox;
            const vw = video.videoWidth;
            const vh = video.videoHeight;
            const centerX = (face.x + face.width / 2) / vw;
            const centerY = (face.y + face.height / 2) / vh;
            const faceRatio = face.width / vw;

            setHasFace(true);
            setFaceData({ centerX, centerY, ratio: faceRatio });

            if (faceRatio > 0.55) setFacePosition('too-close');
            else if (faceRatio < 0.15) setFacePosition('too-far');
            else if (centerX < 0.35) setFacePosition('right');
            else if (centerX > 0.65) setFacePosition('left');
            else if (centerY < 0.25 || centerY > 0.75) setFacePosition('off-center');
            else setFacePosition('centered');
          } else {
            setHasFace(false);
            setFacePosition('none');
            setFaceData(null);
          }
        } else {
          // Fallback: skin-tone pixel analysis in center region
          const canvas = document.createElement('canvas');
          canvas.width = 160;
          canvas.height = 120;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(video, 0, 0, 160, 120);
          const centerData = ctx.getImageData(40, 20, 80, 80);
          const pixels = centerData.data;
          let skinPixels = 0;
          const totalPixels = pixels.length / 4;
          for (let i = 0; i < pixels.length; i += 4) {
            const r = pixels[i], g = pixels[i + 1], b = pixels[i + 2];
            if (r > 80 && g > 40 && b > 20 && r > g && r > b && (r - g) > 10) skinPixels++;
          }
          const skinRatio = skinPixels / totalPixels;
          const detected = skinRatio > 0.12;
          setHasFace(detected);
          setFacePosition(detected ? 'centered' : 'none');
          setFaceData(detected ? { centerX: 0.5, centerY: 0.45, ratio: 0.3 } : null);
        }
      } catch (err) { /* ignore */ }
    };

    const interval = setInterval(detect, 400);
    return () => clearInterval(interval);
  }, [isActive, videoRef]);

  return { faceData, hasFace, facePosition };
}

// ============================================================================
// INTERACTIVE FACE GUIDE COMPONENT
// ============================================================================
function InteractiveFaceGuide({ hasFace, facePosition, targetAngle, faceData }) {
  const getColor = () => {
    if (!hasFace) return '#ff4444';
    if (isReady()) return '#00e676';
    if (facePosition === 'too-close' || facePosition === 'too-far') return '#ff9100';
    return '#ffd740';
  };

  const isReady = () => {
    if (!hasFace || facePosition === 'too-close' || facePosition === 'too-far' || facePosition === 'none') return false;
    if (targetAngle === 'front') return facePosition === 'centered';
    if (targetAngle === 'left') return facePosition === 'left' || facePosition === 'centered';
    if (targetAngle === 'right') return facePosition === 'right' || facePosition === 'centered';
    return true;
  };

  const getMessage = () => {
    if (!hasFace) return '👤 Position your face in the frame';
    if (facePosition === 'too-close') return '↔️ Move back a bit';
    if (facePosition === 'too-far') return '↔️ Come closer';
    if (facePosition === 'off-center') return '⬆️ Center your face';
    if (targetAngle === 'front') {
      if (facePosition === 'centered') return '✅ Perfect! Ready to capture';
      if (facePosition === 'left') return '↩️ Turn slightly right';
      if (facePosition === 'right') return '↪️ Turn slightly left';
    }
    if (targetAngle === 'left') {
      return (facePosition === 'left' || facePosition === 'centered') ? '✅ Great angle! Ready' : '↩️ Turn head 45° left';
    }
    if (targetAngle === 'right') {
      return (facePosition === 'right' || facePosition === 'centered') ? '✅ Great angle! Ready' : '↪️ Turn head 45° right';
    }
    return 'Adjust position';
  };

  const color = getColor();
  const ready = isReady();

  const ox = faceData ? (faceData.centerX - 0.5) * 50 : 0;
  const oy = faceData ? (faceData.centerY - 0.45) * 35 : 0;
  const sc = faceData ? Math.min(Math.max(faceData.ratio / 0.3, 0.75), 1.35) : 1;

  return (
    <div className="face-guide-interactive">
      <svg
        viewBox="0 0 300 400"
        className={`guide-svg-interactive ${ready ? 'guide-ready' : ''}`}
        style={{ transform: `translate(${ox}px, ${oy}px) scale(${sc})`, transition: 'transform 0.3s ease-out' }}
      >
        <defs>
          <filter id="glow"><feGaussianBlur stdDeviation="4" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
        </defs>

        {/* Main guide ellipse */}
        <ellipse cx="150" cy="165" rx="80" ry="105"
          fill="none" stroke={color}
          strokeWidth={ready ? 3.5 : 2}
          strokeDasharray={ready ? 'none' : '10,8'}
          opacity={ready ? 1 : 0.5}
          filter={ready ? 'url(#glow)' : 'none'}
          style={{ transition: 'all 0.4s ease' }}
        />

        {/* Crosshair for front */}
        {targetAngle === 'front' && (
          <g opacity="0.2" stroke={color} strokeWidth="0.8">
            <line x1="150" y1="80" x2="150" y2="250"/>
            <line x1="75" y1="165" x2="225" y2="165"/>
          </g>
        )}

        {/* Turn arrow for left */}
        {targetAngle === 'left' && (
          <g opacity="0.7" stroke={color} fill="none" strokeWidth="2.5">
            <path d="M 85 110 Q 55 165 85 220" strokeDasharray="6,4"/>
            <polygon points="80,108 90,108 85,95" fill={color} stroke="none"/>
            <text x="45" y="170" fill={color} fontSize="14" fontWeight="600" opacity="0.8">45°</text>
          </g>
        )}

        {/* Turn arrow for right */}
        {targetAngle === 'right' && (
          <g opacity="0.7" stroke={color} fill="none" strokeWidth="2.5">
            <path d="M 215 110 Q 245 165 215 220" strokeDasharray="6,4"/>
            <polygon points="210,108 220,108 215,95" fill={color} stroke="none"/>
            <text x="235" y="170" fill={color} fontSize="14" fontWeight="600" opacity="0.8">45°</text>
          </g>
        )}

        {/* Pulsing ring when ready */}
        {ready && (
          <ellipse cx="150" cy="165" rx="90" ry="115" fill="none" stroke={color} strokeWidth="1" opacity="0.4">
            <animate attributeName="rx" values="88;95;88" dur="2s" repeatCount="indefinite"/>
            <animate attributeName="ry" values="113;120;113" dur="2s" repeatCount="indefinite"/>
            <animate attributeName="opacity" values="0.4;0.1;0.4" dur="2s" repeatCount="indefinite"/>
          </ellipse>
        )}
      </svg>

      <div className="guide-message" style={{ background: ready ? 'rgba(0,230,118,0.15)' : 'rgba(0,0,0,0.65)', borderColor: color, color: ready ? '#00e676' : '#fff' }}>
        {getMessage()}
      </div>
    </div>
  );
}

// ============================================================================
// MAIN APP
// ============================================================================
function App() {
  const [step, setStep] = useState('intro');
  const [capturedImages, setCapturedImages] = useState({});
  const [currentAngle, setCurrentAngle] = useState('front');
  const [stream, setStream] = useState(null);
  const [qualityCheck, setQualityCheck] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);
  const [cameraReady, setCameraReady] = useState(false);
  const [analyzeStep, setAnalyzeStep] = useState(0);

  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);

  const { faceData, hasFace, facePosition } = useFaceDetection(videoRef, step === 'capture' && cameraReady);

  const angles = [
    { id: 'front', label: 'Front', instruction: 'Look directly at the camera', icon: '👤' },
    { id: 'left', label: 'Left 45°', instruction: 'Turn your head 45° to the left', icon: '◀ 👤' },
    { id: 'right', label: 'Right 45°', instruction: 'Turn your head 45° to the right', icon: '👤 ▶' }
  ];

  useEffect(() => {
    return () => {
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    };
  }, []);

  const startCamera = async () => {
    try {
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      setCameraReady(false);
      setError(null);
      const ms = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 1280, min: 640 }, height: { ideal: 720, min: 480 }, facingMode: 'user' }
      });
      streamRef.current = ms;
      setStream(ms);
      setStep('capture');
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = ms;
          videoRef.current.onloadedmetadata = () => {
            videoRef.current.play().then(() => setCameraReady(true)).catch(() => setError('Failed to start video.'));
          };
        }
      }, 100);
    } catch (err) {
      if (err.name === 'NotAllowedError') setError('Camera access denied. Allow camera permissions and try again.');
      else if (err.name === 'NotFoundError') setError('No camera found.');
      else setError(`Camera error: ${err.message}`);
    }
  };

  useEffect(() => {
    if (step === 'capture' && videoRef.current && streamRef.current && !videoRef.current.srcObject) {
      videoRef.current.srcObject = streamRef.current;
      videoRef.current.onloadedmetadata = () => {
        videoRef.current.play().then(() => setCameraReady(true)).catch(console.error);
      };
    }
  }, [step]);

  const stopCamera = useCallback(() => {
    if (streamRef.current) { streamRef.current.getTracks().forEach(t => t.stop()); streamRef.current = null; }
    if (videoRef.current) videoRef.current.srcObject = null;
    setStream(null);
    setCameraReady(false);
  }, []);

  // Quality check
  useEffect(() => {
    if (step !== 'capture' || !cameraReady) return;
    const interval = setInterval(async () => {
      try {
        const c = canvasRef.current, v = videoRef.current;
        if (!c || !v || v.readyState !== 4) return;
        c.width = v.videoWidth; c.height = v.videoHeight;
        c.getContext('2d').drawImage(v, 0, 0);
        const blob = await new Promise(r => c.toBlob(r, 'image/jpeg', 0.6));
        if (!blob) return;
        const fd = new FormData();
        fd.append('image', new File([blob], 'qc.jpg', { type: 'image/jpeg' }));
        const res = await fetch(`${API_URL}/api/check-quality`, { method: 'POST', body: fd });
        if (res.ok) setQualityCheck(await res.json());
      } catch(e) {}
    }, 3000);
    return () => clearInterval(interval);
  }, [step, cameraReady]);

  const capturePhoto = () => {
    const c = canvasRef.current, v = videoRef.current;
    if (!c || !v || v.readyState !== 4) return;
    c.width = v.videoWidth; c.height = v.videoHeight;
    c.getContext('2d').drawImage(v, 0, 0);
    const dataUrl = c.toDataURL('image/jpeg', 0.95);
    const newImages = { ...capturedImages, [currentAngle]: dataUrl };
    setCapturedImages(newImages);
    const idx = angles.findIndex(a => a.id === currentAngle);
    if (idx < angles.length - 1) {
      setCurrentAngle(angles[idx + 1].id);
    } else {
      stopCamera();
      analyzeImages(newImages);
    }
  };

  const retakePhoto = (id) => {
    setCapturedImages(prev => { const n = { ...prev }; delete n[id]; return n; });
    setCurrentAngle(id);
  };

  const analyzeImages = async (images) => {
    const imgs = images || capturedImages;
    setStep('analyzing'); setLoading(true); setError(null); setAnalyzeStep(0);
    const t1 = setTimeout(() => setAnalyzeStep(1), 1500);
    const t2 = setTimeout(() => setAnalyzeStep(2), 4000);
    try {
      if (!imgs.front) throw new Error('Front view required');
      const b64 = imgs.front.split(',')[1];
      const bytes = atob(b64);
      const arr = new Uint8Array(bytes.length);
      for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
      const fd = new FormData();
      fd.append('image', new File([arr], 'analysis.jpg', { type: 'image/jpeg' }));
      const res = await fetch(`${API_URL}/api/analyze`, { method: 'POST', body: fd });
      if (!res.ok) { const e = await res.json(); throw new Error(e.error || 'Analysis failed'); }
      const data = await res.json();
      setAnalysis({ ...data.analysis, capturedImages: imgs });
      setStep('results');
    } catch (err) {
      setError(err.message);
      setStep('intro');
    } finally {
      setLoading(false); clearTimeout(t1); clearTimeout(t2);
    }
  };

  const reset = () => {
    stopCamera(); setCapturedImages({}); setCurrentAngle('front');
    setAnalysis(null); setError(null); setQualityCheck(null); setCameraReady(false); setStep('intro');
  };

  const canCapture = cameraReady && hasFace && (
    facePosition === 'centered' ||
    (currentAngle === 'left' && (facePosition === 'left' || facePosition === 'centered')) ||
    (currentAngle === 'right' && (facePosition === 'right' || facePosition === 'centered'))
  );

  return (
    <div className="App">
      {/* ====== INTRO ====== */}
      {step === 'intro' && (
        <div className="intro-screen">
          <div className="intro-content">
            <div className="intro-badge">AI-POWERED</div>
            <h1>Skin Analysis</h1>
            <p className="subtitle">Professional dermatological insights using advanced computer vision</p>
            <div className="features">
              {[
                { icon: '👁️', title: 'Face Detection', desc: 'Real-time tracking guides perfect positioning' },
                { icon: '📐', title: 'Multi-Angle', desc: 'Front, left 45° and right 45° coverage' },
                { icon: '🧬', title: 'AI Report', desc: 'Zone-by-zone analysis with recommendations' }
              ].map((f, i) => (
                <div className="feature" key={i}>
                  <div className="feature-icon-wrap"><span className="feature-icon">{f.icon}</span></div>
                  <h3>{f.title}</h3>
                  <p>{f.desc}</p>
                </div>
              ))}
            </div>
            <button className="btn-start" onClick={startCamera}>
              <span>Start Analysis</span>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
            </button>
            <div className="tips">
              <h4>For best results</h4>
              <div className="tips-grid">
                <span className="tip">☀️ Good lighting</span>
                <span className="tip">🧴 Clean face</span>
                <span className="tip">😐 Neutral expression</span>
                <span className="tip">📱 Hold steady</span>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ====== CAPTURE ====== */}
      {step === 'capture' && (
        <div className="capture-screen">
          <div className="capture-header">
            <button className="btn-back" onClick={() => { stopCamera(); reset(); }}>← Back</button>
            <h2>Capture</h2>
            <div className="capture-step-pills">
              {angles.map((a) => (
                <span key={a.id} className={`step-pill ${capturedImages[a.id] ? 'done' : ''} ${currentAngle === a.id ? 'current' : ''}`}>
                  {capturedImages[a.id] ? '✓' : ''} {a.label}
                </span>
              ))}
            </div>
          </div>

          <div className="capture-container">
            <div className="video-container">
              <video ref={videoRef} autoPlay playsInline muted className="video-feed" />
              <canvas ref={canvasRef} style={{ display: 'none' }} />

              {!cameraReady && (
                <div className="camera-loading"><div className="spinner"></div><p>Starting camera...</p></div>
              )}

              {cameraReady && (
                <InteractiveFaceGuide hasFace={hasFace} facePosition={facePosition} targetAngle={currentAngle} faceData={faceData} />
              )}

              {qualityCheck?.quality?.resolution && (
                <div className="quality-badges">
                  <span className={`q-badge ${qualityCheck.quality.lighting.isGood ? 'good' : 'warn'}`}>
                    {qualityCheck.quality.lighting.isGood ? '☀️' : '🌑'} Light
                  </span>
                  <span className={`q-badge ${qualityCheck.quality.sharpness.isGood ? 'good' : 'warn'}`}>
                    {qualityCheck.quality.sharpness.isGood ? '🔍' : '🌫️'} Focus
                  </span>
                </div>
              )}
            </div>

            <div className="capture-sidebar">
              <div className="sidebar-section current-instruction">
                <div className="angle-icon-large">{angles.find(a => a.id === currentAngle)?.icon}</div>
                <h3>{angles.find(a => a.id === currentAngle)?.label}</h3>
                <p>{angles.find(a => a.id === currentAngle)?.instruction}</p>
              </div>

              <button className={`btn-capture ${canCapture ? 'ready' : ''}`} onClick={capturePhoto} disabled={!cameraReady}>
                <span className="capture-ring"><span className="capture-inner" /></span>
                <span>{!cameraReady ? 'Starting...' : canCapture ? '📸 Capture' : hasFace ? '⬆ Adjust position' : '👤 No face detected'}</span>
              </button>

              <div className="thumbnails">
                {angles.map(angle => (
                  <div key={angle.id} className={`thumbnail ${capturedImages[angle.id] ? 'has-image' : ''} ${currentAngle === angle.id ? 'current' : ''}`}>
                    {capturedImages[angle.id] ? (
                      <>
                        <img src={capturedImages[angle.id]} alt={angle.label} />
                        <button className="btn-retake" onClick={() => retakePhoto(angle.id)}>↻</button>
                        <span className="thumb-check">✓</span>
                      </>
                    ) : (
                      <div className="thumbnail-placeholder">
                        <span className="thumb-label">{angle.label}</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ====== ANALYZING ====== */}
      {step === 'analyzing' && (
        <div className="analyzing-screen">
          <div className="analyzing-content">
            {capturedImages.front && (
              <div className="analyze-face-preview">
                <img src={capturedImages.front} alt="Your face" />
                <div className="scan-line" />
              </div>
            )}
            <h2>Analyzing Your Skin</h2>
            <p className="analyze-sub">AI is examining your facial features</p>
            <div className="analyzing-steps">
              {['Image quality verified', 'Detecting skin issues', 'Generating recommendations'].map((label, i) => (
                <div key={i} className={`analyzing-step ${analyzeStep >= i ? 'active' : ''} ${analyzeStep > i ? 'done' : ''}`}>
                  <span className="step-dot">{analyzeStep > i ? '✓' : analyzeStep === i ? '●' : '○'}</span>
                  {label}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ====== RESULTS ====== */}
      {step === 'results' && analysis && (
        <div className="results-screen">
          <div className="results-header">
            <div>
              <h1>Skin Analysis Report</h1>
              <p className="results-date">{new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
            </div>
            <button className="btn-new" onClick={reset}>+ New Analysis</button>
          </div>

          <div className="results-content">
            {/* Captured Photos */}
            {analysis.capturedImages && (
              <div className="card report-photos-card">
                <h2>📸 Captured Photos</h2>
                <div className="report-photos">
                  {angles.map(a => analysis.capturedImages[a.id] && (
                    <div key={a.id} className="report-photo">
                      <img src={analysis.capturedImages[a.id]} alt={a.label} />
                      <span className="report-photo-label">{a.label}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Score */}
            <div className="card score-card">
              <h2>Overall Skin Health</h2>
              <div className="score-circle">
                <svg viewBox="0 0 200 200">
                  <circle cx="100" cy="100" r="80" fill="none" stroke="rgba(255,255,255,0.15)" strokeWidth="16"/>
                  <circle cx="100" cy="100" r="80" fill="none"
                    stroke={analysis.overallScore >= 70 ? '#00e676' : analysis.overallScore >= 40 ? '#ff9100' : '#ff4466'}
                    strokeWidth="16" strokeLinecap="round"
                    strokeDasharray={`${(analysis.overallScore / 100) * 502} 502`}
                    transform="rotate(-90 100 100)"
                    style={{ transition: 'stroke-dasharray 1.5s ease' }}
                  />
                </svg>
                <div className="score-text">
                  <div className="score-number">{analysis.overallScore}</div>
                  <div className="score-label">/ 100</div>
                </div>
              </div>
              <p className="score-summary">{analysis.summary}</p>
              <div className="skin-type">Skin Type: <strong>{analysis.skinType}</strong></div>
            </div>

            {/* Issues */}
            <div className="card">
              <h2>🔍 Detected Issues</h2>
              {analysis.detectedIssues?.length > 0 ? (
                <div className="issues-list">
                  {analysis.detectedIssues.map((issue, i) => (
                    <div key={i} className={`issue-item severity-${issue.severity}`}>
                      <div className="issue-header"><h3>{issue.issue}</h3><span className="severity-badge">{issue.severity}</span></div>
                      <p>{issue.description}</p>
                      {issue.affected_areas?.length > 0 && <div className="affected-areas">Affected: {issue.affected_areas.join(', ')}</div>}
                    </div>
                  ))}
                </div>
              ) : <p className="no-issues">✨ No significant issues detected!</p>}
            </div>

            {/* Zones */}
            {analysis.zoneAnalysis && (
              <div className="card">
                <h2>📍 Facial Zone Analysis</h2>
                <div className="zones-grid">
                  {Object.entries(analysis.zoneAnalysis).map(([zone, data]) => (
                    <div key={zone} className={`zone-card condition-${data.condition}`}>
                      <h3>{zone.replace(/([A-Z])/g, ' $1').trim()}</h3>
                      <div className="zone-score">{data.score}<span>/10</span></div>
                      <div className="zone-condition">{data.condition}</div>
                      {data.issues?.length > 0 && <ul className="zone-issues">{data.issues.map((is, i) => <li key={i}>{is}</li>)}</ul>}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Treatments */}
            {analysis.treatmentRecommendations?.length > 0 && (
              <div className="card">
                <h2>💆 Treatment Recommendations</h2>
                <div className="treatments-list">
                  {analysis.treatmentRecommendations.map((t, i) => (
                    <div key={i} className="treatment-item"><h3>{t.treatment}</h3><p><strong>Purpose:</strong> {t.purpose}</p><p><strong>Frequency:</strong> {t.frequency}</p></div>
                  ))}
                </div>
              </div>
            )}

            {/* Routine */}
            {analysis.homeCareRoutine && (
              <div className="card">
                <h2>🏠 Home Care Routine</h2>
                <div className="routine-grid">
                  <div className="routine-section"><h3>☀️ Morning</h3><ol>{analysis.homeCareRoutine.morning.map((s, i) => <li key={i}>{s}</li>)}</ol></div>
                  <div className="routine-section"><h3>🌙 Evening</h3><ol>{analysis.homeCareRoutine.evening.map((s, i) => <li key={i}>{s}</li>)}</ol></div>
                </div>
              </div>
            )}

            {/* Lifestyle */}
            {analysis.lifestyleSuggestions && (
              <div className="card">
                <h2>🌟 Lifestyle</h2>
                <div className="lifestyle-grid">
                  {Object.entries(analysis.lifestyleSuggestions).map(([cat, items]) => (
                    <div key={cat} className="lifestyle-section">
                      <h3>{cat.charAt(0).toUpperCase() + cat.slice(1)}</h3>
                      <ul>{items.map((s, i) => <li key={i}>{s}</li>)}</ul>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Timeline */}
            {analysis.progressTimeline && (
              <div className="card">
                <h2>📈 Progress Timeline</h2>
                <div className="timeline">
                  {Object.entries(analysis.progressTimeline).map(([period, changes]) => (
                    <div key={period} className="timeline-item">
                      <div className="timeline-marker" />
                      <div className="timeline-content"><h3>{period.replace(/([A-Z])/g, ' $1').trim()}</h3><p>{changes}</p></div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          <div className="results-footer">
            <button className="btn-primary" onClick={reset}>Start New Analysis</button>
            <button className="btn-secondary" onClick={() => window.print()}>📄 Print Report</button>
          </div>
        </div>
      )}

      {error && (
        <div className="error-toast">
          <span>⚠️ {error}</span>
          <button onClick={() => setError(null)}>✕</button>
        </div>
      )}
    </div>
  );
}

export default App;
